}

text:
{pkgs, ...}: {
  wayland.windowManager.hyprland = {
    enable = true;
    configType = "hyprlang";
    systemd.enable = false;
    systemd.variables = ["--all"];

    settings = {
      # ### MONITORS ###
      # monitor = [
      #   "DP-2,5120x2160@120,0x0,1.25"
      #   "eDP-1,2560x1600@165,4096x728,1.6"
      # ];

      monitor = [
        "DP-2,5120x2160@120,0x0,1.25"
        "eDP-1,2560x1600@165,4096x728,1.6"
      ];

      ### VARIABLES ###
      "$terminal" = "ghostty";
      "$browser" = "google-chrome-stable";
      "$fileManager" = "ghostty --class=dev.me.file --title=File -e /home/ian/.nix-profile/bin/yazi-open";
      "$fileManagergraphic" = "nautilus";
      "$calculator" = "ghostty --class=dev.me.calc --title=Calculator -e kalker";
      "$menu" = "${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleLauncher";
      "$editor" = "zeditor";
      "$audio" = "pgrep -x pulsemixer >/dev/null 2>&1 || ghostty --class=dev.me.audio --title=Audio -e pulsemixer";
      "$settings" = "cosmic-settings";

      ### AUTOSTART ###
      "exec-once" = [
        "uwsm finalize"
        "xhost +local:"
        "${pkgs.xrdb}/bin/xrdb -merge /home/ian/.Xresources"
      ];

      ### STATIC WORKSPACES ###
      workspace = [
        "5, monitor:eDP-1, persistent:true"
        "6, monitor:eDP-1, persistent:true"
        "7, monitor:eDP-1, persistent:true"
        "8, monitor:eDP-1, persistent:true"
        "1, monitor:DP-2, persistent:true"
        "2, monitor:DP-2, persistent:true"
        "3, monitor:DP-2, persistent:true"
        "4, monitor:DP-2, persistent:true"
      ];

      ### ENVIRONMENT ###
      env = [
        "HYPRCURSOR_THEME,catppuccin-macchiato-dark-cursors"
        "HYPRCURSOR_SIZE,24"
        "XCURSOR_THEME,catppuccin-macchiato-dark-cursors"
        "XCURSOR_SIZE,24"
        "EDITOR,zeditor"
        "TERMINAL,ghostty"
        "BROWSER,google-chrome-stable"
        "GTK_USE_PORTAL,1"
        "NIXOS_XDG_OPEN_USE_PORTAL,1"
        "ELECTRON_OZONE_PLATFORM_HINT,wayland"
        "XDG_CURRENT_DESKTOP,Hyprland"
        # NVIDIA tweaks
        "LIBVA_DRIVER_NAME,nvidia"
        "XDG_SESSION_TYPE,wayland"
        "GBM_BACKEND,nvidia-drm"
        "__GLX_VENDOR_LIBRARY_NAME,nvidia"
      ];

      ### CURSOR ###
      cursor.no_hardware_cursors = true;

      ### GENERAL LOOK-AND-FEEL ###
      general = {
        gaps_in = 5;
        gaps_out = "10,10,10,10";
        border_size = 4;
        "col.active_border" = "rgba(33ff33ff)";
        "col.inactive_border" = "rgba(888888aa)";
        resize_on_border = true;
        allow_tearing = false;
        layout = "dwindle";
      };

      decoration = {
        rounding = 10;
        active_opacity = 1.0;
        inactive_opacity = 1.0;
        dim_special = 0.4;
        dim_around = 0.55;
        shadow = {
          enabled = false;
        };
        blur = {
          enabled = true;
          size = 4;
          passes = 2;
          ignore_opacity = true;
        };
      };

      animations.enabled = true;
      bezier = [
        "quick,0.15,0,0.1,1"
        "easeOutQuint,0.23,1,0.32,1"
        "easeInOutCubic,0.65,0.05,0.36,1"
        "linear,0,0,1,1"
        "almostLinear,0.5,0.5,0.75,1.0"
      ];

      animation = [
        "windows,1,7,default,popin"
        "border,0"
        "fade,1,4,default"
        "workspaces,1,6,default,slide"
        "specialWorkspace,1,6,default,slidevert"
        "layers,0.5,6,default,fade"
      ];

      dwindle = {
        preserve_split = true;
      };

      misc = {
        focus_on_activate = true;
        force_default_wallpaper = 0;
        disable_hyprland_logo = true;
        disable_splash_rendering = true;
      };

      xwayland = {
        force_zero_scaling = true;
      };

      ecosystem = {
        no_update_news = true;
        no_donation_nag = true;
      };

      ### INPUT ###
      input = {
        kb_layout = "us";
        kb_options = "compose:caps";
        follow_mouse = 1;
        sensitivity = 0.8;
        touchpad.natural_scroll = false;
      };

      ### KEYBINDINGS ###
      "$mainMod" = "SUPER";

      binde = [
        ",XF86AudioRaiseVolume,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar volumeUp"
        ",XF86AudioLowerVolume,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar volumeDown"
        ",XF86MonBrightnessUp,exec,${pkgs.brightnessctl}/bin/brightnessctl set +5%; ${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar showBrightness"
        ",XF86MonBrightnessDown,exec,${pkgs.brightnessctl}/bin/brightnessctl set 5%-; ${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar showBrightness"
      ];

      bind = [
        ",XF86AudioPlay,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaPlayPause"
        ",XF86AudioNext,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaNext"
        ",XF86AudioPrev,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaPrevious"
        ",XF86AudioMute,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleAudioMute"
        ",PRINT,exec,hyprshot -m region -o ~/Pictures/Screenshots"
        "$mainMod,RETURN,exec,$terminal"
