    hideAppLauncher();
    hideMediaOverlay();
    hideWifiSelector();
    hideUpdateSelector();
    hideVolumeOverlay();
    hideBrightnessOverlay();
    hideDebugOverlay();
    bluetoothTargetMonitor = resolvedTarget;
    bluetoothSelectorVisible = true;
    bluetoothTab = 0;
    bluetoothSelectedIndex = 0;
    refreshBluetoothSelectorDevices(false, true);
